import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";

function Schedules() {
  const user = useSelector((state) => state.auth.user);
  const [schedules, setSchedules] = useState([]);
  const [courses, setCourses] = useState([]);
  const [classes, setClasses] = useState([]);
  const [newSchedule, setNewSchedule] = useState({
    courseId: "",
    classId: "",
    dateTime: "",
  });

  useEffect(() => {
    fetch("http://localhost:3001/schedules")
      .then((res) => res.json())
      .then((data) => {
        // Ensure data is an array
        setSchedules(Array.isArray(data) ? data : []);
      })
      .catch((error) => {
        toast.error("Ошибка загрузки расписания");
        setSchedules([]);
      });
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(Array.isArray(data) ? data : []))
      .catch((error) => toast.error("Ошибка загрузки курсов"));
    fetch("http://localhost:3001/classes")
      .then((res) => res.json())
      .then((data) => setClasses(Array.isArray(data) ? data : []))
      .catch((error) => toast.error("Ошибка загрузки классов"));
  }, []);

  async function handleCreateSchedule(e) {
    e.preventDefault();
    if (!newSchedule.courseId || !newSchedule.classId || !newSchedule.dateTime) {
      toast.error("Заполните все поля!");
      return;
    }
    try {
      const response = await fetch("http://localhost:3001/schedules", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          courseId: parseInt(newSchedule.courseId),
          classId: parseInt(newSchedule.classId),
          dateTime: newSchedule.dateTime,
        }),
      });
      if (response.ok) {
        const createdSchedule = await response.json();
        setSchedules([...schedules, createdSchedule]);
        setNewSchedule({ courseId: "", classId: "", dateTime: "" });
        toast.success("Расписание добавлено!");
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Расписание для курса "${courses.find((c) => c.id === parseInt(newSchedule.courseId))?.name}" добавлено.`,
            createdAt: new Date().toISOString(),
          }),
        });
      } else {
        toast.error("Не удалось добавить расписание");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при добавлении расписания");
    }
  }

  async function handleDeleteSchedule(id) {
    try {
      const response = await fetch(`http://localhost:3001/schedules/${id}`, {
        method: "DELETE",
      });
      if (response.ok) {
        setSchedules(schedules.filter((s) => s.id !== id));
        toast.success("Расписание удалено!");
      } else {
        toast.error("Не удалось удалить расписание");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при удалении расписания");
    }
  }

  if (user?.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Расписание</h1>
      <div className="row">
        <div className="col-md-6">
          <div className="card shadow mb-4">
            <div className="card-body">
              <h2 className="card-title">Добавить расписание</h2>
              <form onSubmit={handleCreateSchedule}>
                <div className="mb-3">
                  <label htmlFor="course" className="form-label">Курс</label>
                  <select
                    id="course"
                    className="form-select"
                    value={newSchedule.courseId}
                    onChange={(e) => setNewSchedule({ ...newSchedule, courseId: e.target.value })}
                    required
                  >
                    <option value="">-- Выберите курс --</option>
                    {courses.map((course) => (
                      <option key={course.id} value={course.id}>
                        {course.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="mb-3">
                  <label htmlFor="class" className="form-label">Класс</label>
                  <select
                    id="class"
                    className="form-select"
                    value={newSchedule.classId}
                    onChange={(e) => setNewSchedule({ ...newSchedule, classId: e.target.value })}
                    required
                  >
                    <option value="">-- Выберите класс --</option>
                    {classes.map((cls) => (
                      <option key={cls.id} value={cls.id}>
                        {cls.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="mb-3">
                  <label htmlFor="dateTime" className="form-label">Дата и время</label>
                  <input
                    type="datetime-local"
                    id="dateTime"
                    className="form-control"
                    value={newSchedule.dateTime}
                    onChange={(e) => setNewSchedule({ ...newSchedule, dateTime: e.target.value })}
                    required
                  />
                </div>
                <button type="submit" className="btn btn-primary w-100">Добавить</button>
              </form>
            </div>
          </div>
        </div>
        <div className="col-md-6">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title">Список расписаний</h2>
              {schedules.length === 0 ? (
                <p>Расписаний нет</p>
              ) : (
                <ul className="list-group">
                  {schedules.map((schedule) => (
                    <li key={schedule.id} className="list-group-item d-flex justify-content-between align-items-center">
                      <div>
                        <strong>Курс:</strong> {courses.find((c) => c.id === schedule.courseId)?.name || "Неизвестный курс"}<br />
                        <strong>Класс:</strong> {classes.find((c) => c.id === schedule.classId)?.name || "Неизвестный класс"}<br />
                        <strong>Дата и время:</strong> {new Date(schedule.dateTime).toLocaleString()}
                      </div>
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => handleDeleteSchedule(schedule.id)}
                      >
                        Удалить
                      </button>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Schedules;
